('66666666-6666-6666-6666-666666666666', 'aisha', 'aisha@horizon.blog', '$2a$10$dXJ3SW6G7P50lGmMkkmwe.u0v2jvIei6irMIXja2fJGZveHFkNj2a', 'Aisha M.', 'Engineer and writer connecting code, craft, and creative practice.', 'https://images.unsplash.com/photo-1488426862026-3ee34a7d66df', 'USER', '2025-03-11 13:00:00', '2026-03-07 13:00:00'),
('77777777-7777-7777-7777-777777777777', 'vikram', 'vikram@horizon.blog', '$2a$10$dXJ3SW6G7P50lGmMkkmwe.u0v2jvIei6irMIXja2fJGZveHFkNj2a', 'Vikram P.', 'Psychology writer focused on imagination, memory, and attention.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d', 'USER', '2025-04-01 09:45:00', '2026-03-06 09:45:00'),
('88888888-8888-8888-8888-888888888888', 'nalini', 'nalini@horizon.blog', '$2a$10$dXJ3SW6G7P50lGmMkkmwe.u0v2jvIei6irMIXja2fJGZveHFkNj2a', 'Nalini K.', 'Historian and urbanist tracing the design intelligence of old cities.', 'https://images.unsplash.com/photo-1491349174775-aaafddd81942', 'USER', '2025-04-18 14:15:00', '2026-03-05 14:15:00'),
