INSERT IGNORE INTO posts (id, title, subtitle, slug, body, cover_image_url, status, visibility, read_time_minutes, view_count, author_id, category_id, created_at, updated_at, published_at) VALUES
('c0000001-0000-0000-0000-000000000001', 'The Expanding Universe of Human Consciousness', 'We stand at the precipice of a new understanding where neuroscience, philosophy, and lived experience converge.', 'the-expanding-universe-of-human-consciousness', 'There is a peculiar vertigo that comes from thinking about thinking. In Horizon Blog''s flagship essay, Aryan traces the tension between neuroscience, phenomenology, and philosophy of mind. The article argues that the most useful progress comes not from flattening consciousness into simple mechanism, but from building better language for describing what conscious life feels like from the inside.', 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee', 'PUBLISHED', 'PUBLIC', 8, 3142, '11111111-1111-1111-1111-111111111111', 'aaaaaaa1-aaaa-aaaa-aaaa-aaaaaaaaaaa1', '2026-03-09 09:00:00', '2026-03-09 09:00:00', '2026-03-09 09:00:00'),
('c0000002-0000-0000-0000-000000000002', 'Building with AI: A Human''s Perspective', 'Why the best AI products still start with empathy, editorial judgment, and human taste.', 'building-with-ai-a-humans-perspective', 'Sana writes about building with AI from the vantage point of people who still need tools to feel legible and trustworthy. She argues that automation becomes most powerful when it extends judgment instead of pretending to replace it, and she offers concrete lessons for writers, designers, and product teams.', 'https://images.unsplash.com/photo-1485827404703-89b55fcc595e', 'PUBLISHED', 'PUBLIC', 5, 1804, '22222222-2222-2222-2222-222222222222', 'aaaaaaa2-aaaa-aaaa-aaaa-aaaaaaaaaaa2', '2026-03-10 10:00:00', '2026-03-10 10:00:00', '2026-03-10 10:00:00'),
('c0000003-0000-0000-0000-000000000003', 'Dark Matter & the Stories We Tell About the Unknown', 'The language we use for the unseen shapes what science feels allowed to imagine next.', 'dark-matter-and-the-stories-we-tell-about-the-unknown', 'Rohan explores how cosmology depends not only on equations but on metaphor. Dark matter remains elusive, yet the stories scientists and the public tell about the unseen determine whether uncertainty feels exciting, terrifying, or fertile.', 'https://images.unsplash.com/photo-1462331940025-496dfbfc7564', 'PUBLISHED', 'PUBLIC', 6, 2400, '33333333-3333-3333-3333-333333333333', 'aaaaaaa3-aaaa-aaaa-aaaa-aaaaaaaaaaa3', '2026-03-09 13:00:00', '2026-03-09 13:00:00', '2026-03-09 13:00:00'),
('c0000004-0000-0000-0000-000000000004', 'The Quiet Revolution of Slow Reading', 'Attention can still be reclaimed, one unhurried page at a time.', 'the-quiet-revolution-of-slow-reading', 'Priya makes the case for slow reading as a cultural practice rather than a productivity hack. She describes how rituals of rereading, annotation, and patient attention can become a form of resistance against the speed of feeds.', 'https://images.unsplash.com/photo-1455885666463-9fe6c5c6e6ef', 'PUBLISHED', 'PUBLIC', 4, 743, '44444444-4444-4444-4444-444444444444', 'aaaaaaa4-aaaa-aaaa-aaaa-aaaaaaaaaaa4', '2026-03-10 12:00:00', '2026-03-10 12:00:00', '2026-03-10 12:00:00'),
('c0000005-0000-0000-0000-000000000005', 'Notes from a Climate Skeptic Turned Believer', 'A personal account of how evidence, weather, and lived reality can change a worldview.', 'notes-from-a-climate-skeptic-turned-believer', 'Dev reflects on the emotional and intellectual journey from climate skepticism to conviction. The piece moves through family arguments, field notes, and scientific reports to show how belief can shift when abstractions become impossible to ignore.', 'https://images.unsplash.com/photo-1473773508845-188df298d2d1', 'PUBLISHED', 'PUBLIC', 7, 3400, '55555555-5555-5555-5555-555555555555', 'aaaaaaa5-aaaa-aaaa-aaaa-aaaaaaaaaaa5', '2026-03-08 08:00:00', '2026-03-08 08:00:00', '2026-03-08 08:00:00'),
('c0000006-0000-0000-0000-000000000006', 'What Coding Taught Me About Writing', 'Structure, refactoring, and revision all belong to the same creative family.', 'what-coding-taught-me-about-writing', 'Aisha connects software craft to editorial craft, arguing that outlines resemble architecture, refactors resemble revisions, and clean prose often emerges from the same patience that clean code requires. It is a practical essay about making thought more readable.', 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3', 'PUBLISHED', 'PUBLIC', 3, 1100, '66666666-6666-6666-6666-666666666666', 'aaaaaaa2-aaaa-aaaa-aaaa-aaaaaaaaaaa2', '2026-03-07 15:00:00', '2026-03-07 15:00:00', '2026-03-07 15:00:00'),
('c0000007-0000-0000-0000-000000000007', 'In Defense of Daydreaming', 'Imagination is not wasted time; it is rehearsal for a richer inner life.', 'in-defense-of-daydreaming', 'Vikram argues that daydreaming deserves protection in an efficiency-first culture. He links wandering attention with creativity, psychological integration, and the small recoveries that make focused work possible later.', 'https://images.unsplash.com/photo-1490730141103-6cac27aaab94', 'PUBLISHED', 'PUBLIC', 5, 892, '77777777-7777-7777-7777-777777777777', 'aaaaaaa6-aaaa-aaaa-aaaa-aaaaaaaaaaa6', '2026-03-06 10:00:00', '2026-03-06 10:00:00', '2026-03-06 10:00:00'),
('c0000008-0000-0000-0000-000000000008', 'The Architecture of Ancient Indian Cities', 'Urban memory survives in street grids, water systems, and the logic of old civic life.', 'the-architecture-of-ancient-indian-cities', 'Nalini studies ancient Indian cities as living design systems. She shows how temple axes, markets, climate-aware building techniques, and water infrastructure reveal a sophisticated understanding of public life that still matters today.', 'https://images.unsplash.com/photo-1467269204594-9661b134dd2b', 'PUBLISHED', 'PUBLIC', 9, 2700, '88888888-8888-8888-8888-888888888888', 'aaaaaaa4-aaaa-aaaa-aaaa-aaaaaaaaaaa4', '2026-03-05 14:30:00', '2026-03-05 14:30:00', '2026-03-05 14:30:00'),
('c0000009-0000-0000-0000-000000000009', 'Mapping the Silence Between Stars', 'Silence, scale, and emptiness can be as meaningful as what shines.', 'mapping-the-silence-between-stars', 'James writes about astronomical silence as something measurable and poetic at the same time. The essay invites readers to look not only at stars but at distance, darkness, and the intervals that make meaning possible.', 'https://images.unsplash.com/photo-1502134249126-9f3755a50d78', 'PUBLISHED', 'PUBLIC', 5, 2100, '99999999-9999-9999-9999-999999999999', 'aaaaaaa3-aaaa-aaaa-aaaa-aaaaaaaaaaa3', '2026-03-04 18:00:00', '2026-03-04 18:00:00', '2026-03-04 18:00:00'),
('c0000010-0000-0000-0000-000000000010', 'The Illusion of Rational Choice', 'Why our confident decisions are often stitched together after the fact.', 'the-illusion-of-rational-choice', 'Aryan examines decision-making through behavioral science and philosophy. He suggests that what feels like clean rationality is often a story assembled after intuition, context, and emotion have already done most of the work.', 'https://images.unsplash.com/photo-1516117172878-fd2c41f4a759', 'PUBLISHED', 'PUBLIC', 6, 1876, '11111111-1111-1111-1111-111111111111', 'aaaaaaa1-aaaa-aaaa-aaaa-aaaaaaaaaaa1', '2026-02-22 09:00:00', '2026-02-22 09:00:00', '2026-02-22 09:00:00'),
('c0000011-0000-0000-0000-000000000011', 'Stoicism in the Age of Algorithms', 'Ancient emotional discipline meets recommendation engines, metrics, and machine-speed life.', 'stoicism-in-the-age-of-algorithms', 'This Horizon essay asks what Stoicism offers when modern life is governed by metrics and algorithmic nudges. Aryan argues for a version of inner steadiness that is not detached from technology but clearer about how systems shape attention.', 'https://images.unsplash.com/photo-1516321497487-e288fb19713f', 'PUBLISHED', 'PUBLIC', 5, 2410, '11111111-1111-1111-1111-111111111111', 'aaaaaaa2-aaaa-aaaa-aaaa-aaaaaaaaaaa2', '2026-02-10 09:30:00', '2026-02-10 09:30:00', '2026-02-10 09:30:00'),
('c0000012-0000-0000-0000-000000000012', 'What Silence Teaches Us', 'The loudest lessons are often learned in the quietest moments.', 'what-silence-teaches-us', 'Aryan''s draft explores stillness, attention, and the ways silence can reveal hidden emotional structure. The piece is unfinished but already reaches for a slower, more contemplative register.', 'https://images.unsplash.com/photo-1500534623283-312aade485b7', 'DRAFT', 'PRIVATE', 4, 0, '11111111-1111-1111-1111-111111111111', 'aaaaaaa6-aaaa-aaaa-aaaa-aaaaaaaaaaa6', '2026-03-12 09:30:00', '2026-03-12 09:30:00', NULL),
('c0000013-0000-0000-0000-000000000013', 'The Geometry of Memory', 'Memory is not a filing cabinet. It is closer to a shifting landscape.', 'the-geometry-of-memory', 'This draft studies recollection as a spatial process shaped by erosion, repetition, and emotional weather. It is intended as a bridge between neuroscience and poetic language.', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa', 'DRAFT', 'PRIVATE', 4, 0, '11111111-1111-1111-1111-111111111111', 'aaaaaaa3-aaaa-aaaa-aaaa-aaaaaaaaaaa3', '2026-03-01 17:00:00', '2026-03-01 17:00:00', NULL);
